import React, { useState } from 'react';
import { KanbanColumn } from '../../types';
import { format, parseISO } from 'date-fns';

interface KanbanWidgetProps {
  title: string;
  columns: KanbanColumn[];
  isExpanded?: boolean;
  onTaskMove?: (taskId: string, newColumnId: string) => void;
}

export const KanbanWidget: React.FC<KanbanWidgetProps> = ({ title, columns, isExpanded = false, onTaskMove }) => {
  const [dragOverColumn, setDragOverColumn] = useState<string | null>(null);

  const getPriorityColor = (p?: string) => {
    switch(p) {
      case 'high': return 'bg-red-50 text-red-600 border-red-100';
      case 'medium': return 'bg-amber-50 text-amber-600 border-amber-100';
      case 'low': return 'bg-emerald-50 text-emerald-600 border-emerald-100';
      default: return 'bg-slate-50 text-slate-500 border-slate-100';
    }
  };

  const renderContent = (text: string) => {
    // Regex to split by URLs (http/https)
    const parts = text.split(/(https?:\/\/[^\s]+)/g);
    return (
      <>
        {parts.map((part, i) => {
          if (part.match(/^https?:\/\//)) {
             return (
               <a 
                 key={i} 
                 href={part} 
                 target="_blank" 
                 rel="noopener noreferrer" 
                 className="text-indigo-600 hover:text-indigo-800 hover:underline relative z-20 break-all"
                 onClick={e => e.stopPropagation()}
               >
                 {part}
               </a>
             );
          }
          return <span key={i}>{part}</span>;
        })}
      </>
    );
  };

  const handleDragStart = (e: React.DragEvent, taskId: string) => {
      e.dataTransfer.setData('taskId', taskId);
      e.dataTransfer.effectAllowed = 'move';
      // Make it semitransparent when dragging
      const target = e.target as HTMLElement;
      setTimeout(() => target.classList.add('opacity-50'), 0);
  };

  const handleDragEnd = (e: React.DragEvent) => {
      const target = e.target as HTMLElement;
      target.classList.remove('opacity-50');
      setDragOverColumn(null);
  };

  const handleDragOver = (e: React.DragEvent, colId: string) => {
      e.preventDefault();
      if (dragOverColumn !== colId) {
          setDragOverColumn(colId);
      }
  };

  const handleDrop = (e: React.DragEvent, colId: string) => {
      e.preventDefault();
      setDragOverColumn(null);
      const taskId = e.dataTransfer.getData('taskId');
      if (taskId && onTaskMove) {
          onTaskMove(taskId, colId);
      }
  };

  return (
    <div className="w-full bg-slate-50/50 border border-slate-200 rounded-2xl p-6 my-6 overflow-x-auto">
      <h3 className="font-black text-[11px] uppercase tracking-widest text-slate-500 mb-6 flex items-center gap-2 px-1">
        <svg className="w-4 h-4 text-indigo-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 17V7m0 10a2 2 0 01-2 2H5a2 2 0 01-2-2V7a2 2 0 012-2h2a2 2 0 012 2m0 10a2 2 0 002 2h2a2 2 0 002-2M9 7a2 2 0 012-2h2a2 2 0 012 2m0 10V7m0 10a2 2 0 002 2h2a2 2 0 002-2V7a2 2 0 00-2-2h-2a2 2 0 00-2 2" /></svg>
        {title}
      </h3>
      <div className="flex gap-6 min-w-max">
        {columns.map((col) => (
          <div 
            key={col.id} 
            className={`w-72 shrink-0 flex flex-col rounded-2xl p-4 border transition-colors duration-200
                ${dragOverColumn === col.id ? 'bg-indigo-50 border-indigo-300 ring-2 ring-indigo-200' : 'bg-slate-100/50 border-slate-200/50'}
            `}
            onDragOver={(e) => handleDragOver(e, col.id)}
            onDrop={(e) => handleDrop(e, col.id)}
            onDragLeave={() => setDragOverColumn(null)}
          >
            <div className="flex justify-between items-center mb-4 px-1">
                <h4 className="font-black text-[10px] text-slate-600 uppercase tracking-[0.15em]">{col.title}</h4>
                <span className="bg-white text-[10px] font-black text-slate-400 px-2 py-0.5 rounded-full border border-slate-200">{col.tasks.length}</span>
            </div>
            <div className={`flex flex-col gap-3 overflow-y-auto pr-1 transition-all duration-300 ${isExpanded ? 'max-h-[750px]' : 'max-h-[500px]'}`}>
              {col.tasks.map((task) => (
                <div 
                    key={task.id} 
                    draggable
                    onDragStart={(e) => handleDragStart(e, task.id)}
                    onDragEnd={handleDragEnd}
                    className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 hover:border-indigo-200 hover:shadow-md transition-all cursor-grab active:cursor-grabbing group select-none"
                >
                  <p className="text-sm font-bold text-slate-800 leading-tight group-hover:text-indigo-700 transition-colors pointer-events-none">
                    {renderContent(task.content)}
                  </p>

                  <div className="mt-4 flex flex-wrap gap-2 items-center pointer-events-none">
                    {task.priority && (
                      <span className={`px-2 py-0.5 rounded-md text-[9px] font-black uppercase tracking-wider border ${getPriorityColor(task.priority)}`}>
                        {task.priority}
                      </span>
                    )}
                    {task.tag && (
                      <span className="px-2 py-0.5 bg-blue-50 text-blue-600 text-[9px] font-black uppercase tracking-wider rounded-md border border-blue-100">
                        {task.tag}
                      </span>
                    )}
                    {task.dueDate && (
                      <div className="ml-auto flex items-center gap-1 text-[9px] font-bold text-slate-400">
                         <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                         {(() => {
                            try { return format(parseISO(task.dueDate), 'MMM d'); }
                            catch (e) { return task.dueDate; }
                         })()}
                      </div>
                    )}
                  </div>
                </div>
              ))}
              {col.tasks.length === 0 && (
                  <div className="py-8 text-center text-[10px] font-bold text-slate-300 italic pointer-events-none">Empty Stage</div>
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

import React, { useMemo } from 'react';
import { WidgetData, WidgetType, MindmapNode, DataStore } from '../../types';
import { GanttWidget } from './GanttWidget';
import { ChartWidget } from './ChartWidget';
import { KanbanWidget } from './KanbanWidget';
import { MindmapWidget } from './MindmapWidget';
import { MapWidget } from './MapWidget';
import { MetricsWidget } from './MetricsWidget';
import { RiskMatrixWidget } from './RiskMatrixWidget';
import { ReferencesWidget } from './ReferencesWidget';
import { ErrorWidget } from './ErrorWidget';
import { CodeWidget } from './CodeWidget';
import { TableWidget } from './TableWidget';

interface WidgetRendererProps {
  widget: WidgetData;
  onMindmapNodeClick?: (node: MindmapNode) => void;
  isExpanded?: boolean;
  projectData?: { stores: DataStore[] }; // Pass the full project data context
  onUpdateRecord?: (storeId: string, recordId: string, field: string, value: any) => void;
}

// --- HYDRATION HELPERS ---

const STATUS_PRIORITY = [
  'backlog', 'todo', 'to do', 'planned', 'open', 'new',
  'in-progress', 'in progress', 'active', 'doing', 'wip', 'developing',
  'review', 'qa', 'testing', 'verify', 'verification',
  'blocked', 'holding', 'on-hold',
  'done', 'completed', 'closed', 'released', 'shipped'
];

const getStatusIndex = (title: string) => {
  const normalized = title.toLowerCase().trim();
  const idx = STATUS_PRIORITY.indexOf(normalized);
  if (idx !== -1) return idx;
  // Try partial match
  return STATUS_PRIORITY.findIndex(s => normalized.includes(s));
};

const hydrateWidget = (widget: WidgetData, stores: DataStore[]): any => {
    // If no data source or invalid data source, return widget as is (Legacy mode)
    if (!widget.dataSource || !widget.dataSource.storeId) return widget;

    const store = stores.find(s => s.id === widget.dataSource!.storeId);
    if (!store) {
        console.warn(`Widget ${widget.title} referenced missing store: ${widget.dataSource!.storeId}`);
        return widget;
    }

    // Convert array-based mapping to Record<widgetKey, storeColumn>
    const mappingArray = widget.dataSource!.fieldMapping || [];
    const mapping: Record<string, string> = {};
    if (Array.isArray(mappingArray)) {
        mappingArray.forEach(m => {
            if (m.widgetKey && m.storeColumn) {
                mapping[m.widgetKey] = m.storeColumn;
            }
        });
    } else {
        // Fallback for single object or legacy map
        const asObj = mappingArray as any;
        if (asObj.widgetKey && asObj.storeColumn) {
             mapping[asObj.widgetKey] = asObj.storeColumn;
        } else {
             Object.assign(mapping, mappingArray);
        }
    }

    const records = store.records || [];

    // Helper to map a record using the field mapping
    const mapRecord = (record: any) => {
        const result: any = { ...record }; // Keep original fields for flexibility
        Object.entries(mapping).forEach(([widgetKey, storeColumn]) => {
            if (storeColumn && record[storeColumn] !== undefined) {
                result[widgetKey] = record[storeColumn];
            }
        });
        return result;
    };

    switch (widget.type) {
        case WidgetType.GANTT:
            return {
                ...widget,
                tasks: records.map(r => {
                    const mapped = mapRecord(r);

                    // Robust fallback logic for common fields if mapping misses them
                    // This handles cases where models use keys like 'start_date' but don't map them to 'start'
                    const findVal = (keys: string[]) => {
                        for (const k of keys) {
                            if (mapped[k] !== undefined && mapped[k] !== null) return mapped[k];
                        }
                        // Case-insensitive fallback
                        const lowerKeys = keys.map(k => k.toLowerCase());
                        for (const k of Object.keys(mapped)) {
                             if (lowerKeys.includes(k.toLowerCase()) && mapped[k] !== undefined && mapped[k] !== null) return mapped[k];
                        }
                        return undefined;
                    };

                    const name = mapped.name || findVal(['task', 'title', 'label', 'content', 'item', 'feature']) || "Untitled Task";
                    const start = mapped.start || findVal(['start_date', 'startDate', 'begin', 'init', 'created_at']);
                    const end = mapped.end || findVal(['end_date', 'endDate', 'finish', 'due', 'dueDate', 'deadline', 'target_date']);
                    const progress = mapped.progress !== undefined ? mapped.progress : findVal(['percent', 'percentage', 'completion', 'done']);
                    const status = mapped.status || findVal(['state', 'stage']);
                    const owner = mapped.owner || findVal(['assignee', 'user', 'who', 'lead']);

                    return {
                        id: mapped.id || r.id || String(Math.random()),
                        name: String(name),
                        start: start,
                        end: end,
                        progress: progress ? Number(progress) : 0,
                        owner: owner,
                        status: status,
                        isEstimated: mapped.isEstimated,
                        dependencies: mapped.dependencies
                    };
                })
            };

        case WidgetType.METRICS:
            return {
                ...widget,
                contentItems: records.map(r => {
                    const mapped = mapRecord(r);
                    return {
                        label: mapped.label || "Metric",
                        value: mapped.value,
                        trend: mapped.trend,
                        status: mapped.status,
                        description: mapped.description
                    };
                })
            };

        case WidgetType.REFERENCES:
            return {
                ...widget,
                contentItems: records.map(r => {
                    const mapped = mapRecord(r);
                    return {
                        title: mapped.title || "Reference",
                        uri: mapped.uri || "#",
                    };
                })
            };

        case WidgetType.RISK_MATRIX:
            return {
                ...widget,
                risks: records.map(r => {
                    const mapped = mapRecord(r);
                    return {
                        id: mapped.id || r.id,
                        label: mapped.label || "Risk",
                        impact: Number(mapped.impact),
                        likelihood: Number(mapped.likelihood),
                        mitigation: mapped.mitigation
                    };
                })
            };

        case WidgetType.MAP:
            return {
                ...widget,
                markers: records.map(r => {
                    const mapped = mapRecord(r);
                    return {
                        id: mapped.id || r.id,
                        label: mapped.label || "Location",
                        address: mapped.address,
                        latitude: Number(mapped.latitude),
                        longitude: Number(mapped.longitude),
                        description: mapped.description,
                        type: mapped.type
                    };
                })
            };

        case WidgetType.TABLE:
            // For tables, if mapping exists, we use it to construct the view
            const hasMapping = Object.keys(mapping).length > 0;
            // If mapping exists, the headers are the widgetKeys. Otherwise use store schema.
            const headers = hasMapping ? Object.keys(mapping) : Object.keys(store.schema || records[0] || {});

            const tableRows = records.map(r => {
                if (!hasMapping) return r;
                const row: any = {};
                headers.forEach(h => {
                     // For table, keys in mapping are the headers we want to show
                     const col = mapping[h]; 
                     row[h] = r[col];
                });
                return row;
            });

            return {
                ...widget,
                data: {
                    headers: headers,
                    rows: tableRows,
                    columnTypes: {} 
                }
            };

        case WidgetType.CHART:
            const chartData = records;
            const chartConfig = { ...widget.config };

            // Auto-detect dataKeys if missing to prevent "No data keys defined" error
            if (!chartConfig.dataKeys || chartConfig.dataKeys.length === 0) {
                 const potentialKeys = new Set<string>();

                 // Strategy 1: Look at Field Mapping
                 // The UI Agent often maps 'value', 'y', or 'data' to the metric column
                 if (Object.keys(mapping).length > 0) {
                     ['value', 'y', 'data', 'count', 'score', 'metric', 'amount'].forEach(key => {
                         if (mapping[key]) potentialKeys.add(mapping[key]);
                     });
                 }

                 // Strategy 2: Scan Data (Fallback or Supplement)
                 // Scan up to 10 rows to find keys that hold numeric values
                 if (potentialKeys.size === 0) {
                     const xKey = chartConfig.xAxisKey;
                     for (let i = 0; i < Math.min(chartData.length, 10); i++) {
                         const row = chartData[i];
                         if (!row) continue;
                         Object.keys(row).forEach(k => {
                             if (k === 'id' || k === xKey) return;
                             const val = row[k];
                             // Check if number or parsable string (handling potential nulls safely)
                             if (val !== null && val !== undefined && (typeof val === 'number' || (typeof val === 'string' && !isNaN(Number(val))))) {
                                 potentialKeys.add(k);
                             }
                         });
                     }
                 }

                 if (potentialKeys.size > 0) {
                     chartConfig.dataKeys = Array.from(potentialKeys);
                 }
            }

            return {
                ...widget,
                config: chartConfig,
                data: chartData
            };

        case WidgetType.KANBAN:
            // Group By Logic
            const groupBy = (widget.dataSource as any).groupByField || 'status';
            const mappedRecords = records.map(r => mapRecord(r));

            // Get unique groups
            const groups = Array.from(new Set(mappedRecords.map((r: any) => r[groupBy] || 'Uncategorized')));

            const columns = groups.map(group => ({
                id: String(group),
                title: String(group).toUpperCase(),
                tasks: mappedRecords
                    .filter((r: any) => (r[groupBy] || 'Uncategorized') === group)
                    .map((r: any) => ({
                        id: r.id || String(Math.random()),
                        content: r.content || r.title || r.name || r.task || "No Content",
                        tag: r.tag,
                        priority: r.priority,
                        dueDate: r.dueDate
                    }))
            }));

            // Sort Columns by Workflow Status Priority
            columns.sort((a, b) => {
                const idxA = getStatusIndex(a.title);
                const idxB = getStatusIndex(b.title);

                if (idxA !== -1 && idxB !== -1) return idxA - idxB;
                if (idxA !== -1) return -1;
                if (idxB !== -1) return 1;
                return 0; // Maintain default/insertion order if not found
            });

            return {
                ...widget,
                columns
            };

        default:
            return widget;
    }
};


export const WidgetRenderer: React.FC<WidgetRendererProps> = ({ widget, onMindmapNodeClick, isExpanded, projectData, onUpdateRecord }) => {
  // Hydrate the widget data from the store if a dataSource is present
  const hydratedWidget = useMemo(() => {
     if (projectData && projectData.stores && widget.dataSource) {
         return hydrateWidget(widget, projectData.stores);
     }
     return widget;
  }, [widget, projectData]);

  if (!hydratedWidget) return null;

  switch (hydratedWidget.type) {
    case WidgetType.GANTT:
      return <GanttWidget title={hydratedWidget.title} tasks={hydratedWidget.tasks || []} />;
    case WidgetType.CHART:
      return <ChartWidget title={hydratedWidget.title} config={hydratedWidget.config} data={hydratedWidget.data || []} isExpanded={isExpanded} />;
    case WidgetType.KANBAN:
        return (
            <KanbanWidget 
                title={hydratedWidget.title} 
                columns={hydratedWidget.columns || []} 
                isExpanded={isExpanded}
                onTaskMove={(taskId, newStatus) => {
                    const ds = hydratedWidget.dataSource;
                    if (onUpdateRecord && ds && ds.storeId && ds.groupByField) {
                         onUpdateRecord(ds.storeId, taskId, ds.groupByField, newStatus);
                    }
                }}
            />
        );
    case WidgetType.TABLE:
        return <TableWidget title={hydratedWidget.title} data={hydratedWidget.data} />;
    case WidgetType.CODE:
        return <CodeWidget title={hydratedWidget.title} code={hydratedWidget.code} dataContext={projectData} />;
    case WidgetType.MINDMAP:
        return <MindmapWidget title={hydratedWidget.title} nodes={hydratedWidget.nodes} onNodeClick={onMindmapNodeClick} />;
    case WidgetType.METRICS:
        return <MetricsWidget title={hydratedWidget.title} items={hydratedWidget.contentItems || []} />;
    case WidgetType.RISK_MATRIX:
        return <RiskMatrixWidget title={hydratedWidget.title} risks={hydratedWidget.risks || []} />;
    case WidgetType.REFERENCES:
        return <ReferencesWidget title={hydratedWidget.title} items={hydratedWidget.contentItems || []} />;
    case WidgetType.MAP:
        return <MapWidget title={hydratedWidget.title} markers={hydratedWidget.markers || []} />;
    case WidgetType.ERROR:
        return <ErrorWidget title={hydratedWidget.title} error={hydratedWidget.error} />;
    default:
      return null;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { ProjectNode, ProjectState, MindmapNode, NodeVisualization, NodeData, WidgetData } from '../types';
import { WidgetRenderer } from './GenerativeUI/WidgetRenderer';
import { DebugOverlay } from './DebugOverlay';
import { ChatTurn } from './ChatTurn';
import { ProjectKnowledgeCard } from './ProjectKnowledgeCard';
import { DataStoreExplorer } from './DataStoreExplorer';
import { SynthesisModal } from './SynthesisModal';
import { ConfirmationModal } from './ConfirmationModal';
import { NodeHeader } from './Layout/NodeHeader';
import { SnapshotBanner } from './Layout/SnapshotBanner';
import { WidgetEditorModal } from './WidgetEditorModal';

interface NodeViewProps {
  node: ProjectNode;
  parentNode?: ProjectNode;
  projectState: ProjectState;
  onSelectNode: (id: string) => void;
  onRegenerate: (input: string) => void;
  onSynthesize: (topic?: string) => void;
  onRefresh: () => void;
  onMindmapNodeClick?: (node: MindmapNode) => void;
  onDeleteChatMessage?: (index: number) => void;
  onDeleteWidget: (nodeId: string, index: number) => void;
  onToggleSidebar: () => void;
  isSidebarOpen: boolean;
  onUpdateNodeData: (nodeId: string, data: any) => void;
  onUpdateNodeViz?: (nodeId: string, viz: any) => void;
  onRevertState: (index: number) => void;
  onShowCleanupModal: () => void;
  onUndoCleanup?: () => void;
}

export const NodeView: React.FC<NodeViewProps> = ({ 
  node, 
  parentNode, 
  projectState, 
  onSelectNode, 
  onRegenerate, 
  onSynthesize, 
  onRefresh,
  onMindmapNodeClick,
  onDeleteChatMessage,
  onDeleteWidget,
  onToggleSidebar,
  isSidebarOpen,
  onUpdateNodeData,
  onUpdateNodeViz,
  onRevertState,
  onShowCleanupModal,
  onUndoCleanup
}) => {
  const [selectedImage, setSelectedImage] = useState<{data: string, name: string} | null>(null);
  const [showDebug, setShowDebug] = useState(false);
  const [showDataExplorer, setShowDataExplorer] = useState(false);
  const [showSynthesisModal, setShowSynthesisModal] = useState(false);
  const [vizMode, setVizMode] = useState<'minimized' | 'normal' | 'large' | 'maximized'>('normal');
  const [showVizDetails, setShowVizDetails] = useState(true);
  const scrollEndRef = useRef<HTMLDivElement>(null);

  const [viewingSnapshot, setViewingSnapshot] = useState<{data: NodeData, viz: NodeVisualization, index: number} | null>(null);
  const [confirmRevertIndex, setConfirmRevertIndex] = useState<number | null>(null);

  // Widget Editor State
  const [widgetEditorOpen, setWidgetEditorOpen] = useState(false);
  const [editingWidgetIndex, setEditingWidgetIndex] = useState<number | null>(null);

  useEffect(() => {
    setViewingSnapshot(null);
    setConfirmRevertIndex(null);
  }, [node.id]);

  useEffect(() => {
    scrollEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [node.chat, node.isLoading, node.id, node.processingStage, viewingSnapshot]);

  const allNodes = (Object.values(projectState.nodes) as ProjectNode[]).sort((a, b) => a.timestamp - b.timestamp);
  const currentIndex = allNodes.findIndex(n => n.id === node.id);

  const handleDownload = (data: string, filename: string) => {
    const link = document.createElement('a');
    link.href = data;
    link.download = filename;
    link.click();
  };

  const handleSaveWidget = (updatedWidget: WidgetData) => {
    if (!onUpdateNodeViz) return;

    const currentWidgets = node.visualization.widgets || [];
    let newWidgets;

    if (editingWidgetIndex !== null) {
        // Edit existing
        newWidgets = [...currentWidgets];
        newWidgets[editingWidgetIndex] = updatedWidget;
    } else {
        // Add new
        newWidgets = [...currentWidgets, updatedWidget];
    }

    onUpdateNodeViz(node.id, { widgets: newWidgets });
    setEditingWidgetIndex(null);
  };

  const handleUpdateRecord = (storeId: string, recordId: string, field: string, value: any) => {
    const stores = activeData?.projectData?.stores || [];
    if (stores.length === 0) return;

    const newStores = stores.map(store => {
        if (store.id === storeId) {
            return {
                ...store,
                records: store.records.map(r => {
                    if (r.id === recordId) {
                        return { ...r, [field]: value };
                    }
                    return r;
                })
            };
        }
        return store;
    });

    // Only allow updating current state, not historical snapshots
    if (!viewingSnapshot) {
        onUpdateNodeData(node.id, { projectData: { stores: newStores } });
    }
  };

  const hasDebugError = !!node.debugInfo?.error;

  const getVizHeight = () => {
     switch(vizMode) {
         case 'minimized': return '48px';
         case 'normal': return '45%';
         case 'large': return '75%';
         case 'maximized': return '100%';
     }
  };

  const VizControl: React.FC<{ 
    mode: typeof vizMode, 
    label: string, 
    icon: React.ReactNode, 
    isActive: boolean 
  }> = ({ mode, label, icon, isActive }) => (
    <button
        onClick={(e) => { e.stopPropagation(); setVizMode(mode); }}
        className={`p-1.5 rounded-lg transition-all ${isActive ? 'bg-indigo-100 text-indigo-600' : 'text-slate-400 hover:text-slate-600 hover:bg-slate-100'}`}
        title={label}
    >
        {icon}
    </button>
  );

  const isMaximized = vizMode === 'maximized' || vizMode === 'large';
  const isFullscreen = vizMode === 'maximized';

  const activeData = viewingSnapshot ? viewingSnapshot.data : node.data;
  const activeViz = viewingSnapshot ? viewingSnapshot.viz : node.visualization;
  const activeProjectData = activeData?.projectData;

  const snapshotIndices = node.chat
    .map((m, i) => (m.visualizationSnapshot && m.dataSnapshot ? i : -1))
    .filter(i => i !== -1);

  const currentSnapshotIndexInList = viewingSnapshot ? snapshotIndices.indexOf(viewingSnapshot.index) : -1;
  const hasPrevSnapshot = viewingSnapshot ? currentSnapshotIndexInList > 0 : snapshotIndices.length > 0;
  const hasNextSnapshot = viewingSnapshot ? true : false;

  const loadSnapshot = (index: number) => {
      const msg = node.chat[index];
      if (msg && msg.visualizationSnapshot && msg.dataSnapshot) {
          setViewingSnapshot({
              viz: msg.visualizationSnapshot,
              data: msg.dataSnapshot,
              index: index
          });
      }
  };

  const handlePrevSnapshot = () => {
    if (!viewingSnapshot) {
        const last = snapshotIndices[snapshotIndices.length - 1];
        if (last !== undefined) loadSnapshot(last);
        return;
    }
    if (currentSnapshotIndexInList > 0) {
        loadSnapshot(snapshotIndices[currentSnapshotIndexInList - 1]);
    }
  };

  const handleNextSnapshot = () => {
     if (!viewingSnapshot) return;
     if (currentSnapshotIndexInList < snapshotIndices.length - 1) {
         loadSnapshot(snapshotIndices[currentSnapshotIndexInList + 1]);
     } else {
         setViewingSnapshot(null);
     }
  };

  const getLoadingText = () => {
      switch(node.processingStage) {
          case 'analyzing': return 'Analyzing project requirements...';
          case 'updating_data': return 'Updating database & schemas...';
          case 'designing_ui': return 'Designing interface components...';
          case 'rendering': return 'Rendering visualizations...';
          default: return 'Gemini is thinking...';
      }
  };

  return (
    <div className="flex flex-col h-full bg-slate-50 relative pb-[110px]">
      <ConfirmationModal 
        isOpen={confirmRevertIndex !== null}
        onConfirm={() => {
            const idx = confirmRevertIndex!;
            setViewingSnapshot(null);
            setTimeout(() => onRevertState(idx), 0);
            setConfirmRevertIndex(null);
        }}
        onCancel={() => setConfirmRevertIndex(null)}
        title="Restore History State"
        message="Are you sure you want to revert to this state? All chat history, data, and visualizations created after this point will be permanently lost."
      />

      {widgetEditorOpen && (
        <WidgetEditorModal 
          isOpen={widgetEditorOpen}
          onClose={() => { setWidgetEditorOpen(false); setEditingWidgetIndex(null); }}
          onSave={handleSaveWidget}
          availableStores={activeProjectData?.stores || []}
          initialWidget={editingWidgetIndex !== null ? activeViz.widgets[editingWidgetIndex] : undefined}
        />
      )}

      <NodeHeader 
        node={node} parentNode={parentNode} allNodes={allNodes} currentIndex={currentIndex}
        isSidebarOpen={isSidebarOpen} onToggleSidebar={onToggleSidebar} onSelectNode={onSelectNode}
        onShowDebug={() => setShowDebug(true)} onShowDataExplorer={() => setShowDataExplorer(true)}
        onRegenerate={() => onRegenerate(node.userInput)} onRefresh={onRefresh}
        onShowSynthesisModal={() => setShowSynthesisModal(true)} onShowCleanupModal={onShowCleanupModal}
        onUndoCleanup={onUndoCleanup} hasDebugError={hasDebugError}
        activeProjectDataLength={activeProjectData?.stores?.length || 0}
      />

      {viewingSnapshot && (
        <SnapshotBanner 
          currentIndex={viewingSnapshot.index} totalSteps={node.chat.length}
          hasPrevSnapshot={hasPrevSnapshot} hasNextSnapshot={hasNextSnapshot}
          onPrevSnapshot={handlePrevSnapshot} onNextSnapshot={handleNextSnapshot}
          onRevert={() => setConfirmRevertIndex(viewingSnapshot.index)}
          onExit={() => setViewingSnapshot(null)}
        />
      )}

      <div className="flex-1 relative overflow-hidden">
        <div 
            className="absolute top-0 left-0 right-0 overflow-y-auto bg-slate-50/50 px-4 pt-6 transition-all duration-300 ease-in-out"
            style={{ bottom: getVizHeight() }}
        >
            <div className="max-w-4xl mx-auto space-y-4 min-h-full pb-10">
                <ChatTurn 
                    message={{ 
                      role: 'user', 
                      text: node.userInput, 
                      timestamp: node.timestamp, 
                      attachments: node.userAttachments
                    }} 
                    onMindmapNodeClick={onMindmapNodeClick} 
                    isDeletable={false}
                    onImageClick={setSelectedImage}
                />

                {(viewingSnapshot ? node.chat.slice(0, viewingSnapshot.index + 1) : node.chat).map((msg, i) => (
                    <ChatTurn 
                        key={`${node.id}-msg-${i}`} 
                        message={msg} 
                        onMindmapNodeClick={onMindmapNodeClick}
                        isDeletable={true}
                        onDelete={() => onDeleteChatMessage?.(i)}
                        onImageClick={setSelectedImage}
                        onViewSnapshot={() => {
                            if (viewingSnapshot?.index === i) setViewingSnapshot(null);
