                                    e.stopPropagation();
                                    setDataKeys(prev => prev.filter(p => p !== k));
                                }}>×</span>
                            </span>
                        ))}
                    </div>
                    {chartMultiSelectOpen && (
                        <div className="absolute top-full left-[33.33%] right-0 mt-1 bg-white border border-slate-200 rounded-lg shadow-xl z-50 max-h-48 overflow-y-auto p-1">
                            {schemaKeys.map(k => (
                                <div 
                                    key={k} 
                                    className={`px-3 py-2 text-sm rounded cursor-pointer hover:bg-slate-50 flex items-center gap-2 ${dataKeys.includes(k) ? 'font-bold text-indigo-600' : 'text-slate-700'}`}
                                    onClick={() => {
                                        if (dataKeys.includes(k)) setDataKeys(prev => prev.filter(p => p !== k));
                                        else setDataKeys(prev => [...prev, k]);
                                    }}
                                >
                                    <div className={`w-4 h-4 rounded border flex items-center justify-center ${dataKeys.includes(k) ? 'bg-indigo-600 border-indigo-600 text-white' : 'border-slate-300'}`}>
                                        {dataKeys.includes(k) && <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>}
                                    </div>
                                    {k}
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>
        </div>
      );
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200" onClick={onClose}>
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg p-6 animate-in zoom-in-95 duration-200 max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
        <div className="flex items-center justify-between mb-6">
            <h3 className="text-lg font-bold text-slate-900">
                {initialWidget ? 'Edit Widget' : 'Add New Widget'}
            </h3>
            <button onClick={onClose} className="p-1.5 hover:bg-slate-100 rounded-lg text-slate-400">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
        </div>

        <div className="space-y-5">
            <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1.5">Widget Title</label>
                <input 
                    type="text" 
                    value={title}
                    onChange={e => setTitle(e.target.value)}
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500"
                    placeholder="e.g., Project Timeline"
                />
            </div>

            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1.5">Widget Type</label>
                    <select 
                        value={type}
                        onChange={e => setType(e.target.value as WidgetType)}
                        className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500"
                    >
                        {WIDGET_TYPES.map(t => (
                            <option key={t.value} value={t.value}>{t.label}</option>
                        ))}
                    </select>
                </div>
                <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1.5">Data Source</label>
                    <select 
                        value={selectedStoreId}
                        onChange={e => {
                            setSelectedStoreId(e.target.value);
                            setMappings({}); // Reset mappings on store change
                        }}
                        className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500"
                    >
                        <option value="">No Source (Static)</option>
                        {availableStores.map(s => (
                            <option key={s.id} value={s.id}>{s.name}</option>
                        ))}
                    </select>
                </div>
            </div>

            {selectedStoreId && (
                <div className="bg-indigo-50/50 rounded-xl p-4 border border-indigo-100">
                    {renderMappingInputs()}
                    {renderChartConfig()}
                </div>
            )}

            {!selectedStoreId && (
                <div className="p-4 bg-amber-50 border border-amber-100 rounded-xl text-xs text-amber-700">
                    <b>Note:</b> Without a data source, this widget will display static data or be empty. Connect a Data Store to make it dynamic.
                </div>
            )}

            <div className="pt-4 flex gap-3">
                <button 
                    onClick={onClose}
                    className="flex-1 py-3 text-sm font-bold text-slate-500 hover:bg-slate-50 rounded-xl transition-colors"
                >
                    Cancel
                </button>
                <button 
                    onClick={handleSave}
                    className="flex-1 py-3 bg-indigo-600 text-white text-sm font-bold rounded-xl shadow-lg shadow-indigo-200 hover:bg-indigo-700 transition-all"
                >
                    Save Widget
                </button>
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useMemo } from 'react';
import { WidgetData, WidgetType, MindmapNode, DataStore } from '../../types';
import { GanttWidget } from './GanttWidget';
import { ChartWidget } from './ChartWidget';
import { KanbanWidget } from './KanbanWidget';
import { MindmapWidget } from './MindmapWidget';
import { MapWidget } from './MapWidget';
import { MetricsWidget } from './MetricsWidget';
import { RiskMatrixWidget } from './RiskMatrixWidget';
import { ReferencesWidget } from './ReferencesWidget';
import { ErrorWidget } from './ErrorWidget';
import { CodeWidget } from './CodeWidget';
import { TableWidget } from './TableWidget';

interface WidgetRendererProps {
  widget: WidgetData;
  onMindmapNodeClick?: (node: MindmapNode) => void;
  isExpanded?: boolean;
  projectData?: { stores: DataStore[] }; // Pass the full project data context
  onUpdateRecord?: (storeId: string, recordId: string, field: string, value: any) => void;
}

// --- HYDRATION HELPERS ---

const STATUS_PRIORITY = [
  'backlog', 'todo', 'to do', 'planned', 'open', 'new',
  'in-progress', 'in progress', 'active', 'doing', 'wip', 'developing',
  'review', 'qa', 'testing', 'verify', 'verification',
  'blocked', 'holding', 'on-hold',
  'done', 'completed', 'closed', 'released', 'shipped'
];

const getStatusIndex = (title: string) => {
  const normalized = title.toLowerCase().trim();
  const idx = STATUS_PRIORITY.indexOf(normalized);
  if (idx !== -1) return idx;
  // Try partial match
  return STATUS_PRIORITY.findIndex(s => normalized.includes(s));
};

const hydrateWidget = (widget: WidgetData, stores: DataStore[]): any => {
    // If no data source or invalid data source, return widget as is (Legacy mode)
    if (!widget.dataSource || !widget.dataSource.storeId) return widget;

    const store = stores.find(s => s.id === widget.dataSource!.storeId);
    if (!store) {
        console.warn(`Widget ${widget.title} referenced missing store: ${widget.dataSource!.storeId}`);
        return widget;
    }

    // Convert array-based mapping to Record<widgetKey, storeColumn>
    const mappingArray = widget.dataSource!.fieldMapping || [];
    const mapping: Record<string, string> = {};
    if (Array.isArray(mappingArray)) {
        mappingArray.forEach(m => {
            if (m.widgetKey && m.storeColumn) {
                mapping[m.widgetKey] = m.storeColumn;
            }
        });
    } else {
        // Fallback for single object or legacy map
        const asObj = mappingArray as any;
        if (asObj.widgetKey && asObj.storeColumn) {
             mapping[asObj.widgetKey] = asObj.storeColumn;
        } else {
             Object.assign(mapping, mappingArray);
        }
    }

    const records = store.records || [];

    // Helper to map a record using the field mapping
    const mapRecord = (record: any) => {
        const result: any = { ...record }; // Keep original fields for flexibility
        Object.entries(mapping).forEach(([widgetKey, storeColumn]) => {
            if (storeColumn && record[storeColumn] !== undefined) {
                result[widgetKey] = record[storeColumn];
            }
        });
        return result;
    };

    switch (widget.type) {
        case WidgetType.GANTT:
            return {
                ...widget,
                tasks: records.map(r => {
                    const mapped = mapRecord(r);

                    // Robust fallback logic for common fields if mapping misses them
                    // This handles cases where models use keys like 'start_date' but don't map them to 'start'
                    const findVal = (keys: string[]) => {
                        for (const k of keys) {
                            if (mapped[k] !== undefined && mapped[k] !== null) return mapped[k];
                        }
                        // Case-insensitive fallback
                        const lowerKeys = keys.map(k => k.toLowerCase());
                        for (const k of Object.keys(mapped)) {
                             if (lowerKeys.includes(k.toLowerCase()) && mapped[k] !== undefined && mapped[k] !== null) return mapped[k];
                        }
                        return undefined;
                    };

                    const name = mapped.name || findVal(['task', 'title', 'label', 'content', 'item', 'feature']) || "Untitled Task";
                    const start = mapped.start || findVal(['start_date', 'startDate', 'begin', 'init', 'created_at']);
                    const end = mapped.end || findVal(['end_date', 'endDate', 'finish', 'due', 'dueDate', 'deadline', 'target_date']);
                    const progress = mapped.progress !== undefined ? mapped.progress : findVal(['percent', 'percentage', 'completion', 'done']);
                    const status = mapped.status || findVal(['state', 'stage']);
                    const owner = mapped.owner || findVal(['assignee', 'user', 'who', 'lead']);

                    return {
                        id: mapped.id || r.id || String(Math.random()),
                        name: String(name),
                        start: start,
                        end: end,
                        progress: progress ? Number(progress) : 0,
                        owner: owner,
                        status: status,
                        isEstimated: mapped.isEstimated,
                        dependencies: mapped.dependencies
                    };
                })
            };

        case WidgetType.METRICS:
            return {
                ...widget,
                contentItems: records.map(r => {
                    const mapped = mapRecord(r);
                    return {
                        label: mapped.label || "Metric",
                        value: mapped.value,
                        trend: mapped.trend,
                        status: mapped.status,
                        description: mapped.description
                    };
                })
            };

        case WidgetType.REFERENCES:
            return {
                ...widget,
                contentItems: records.map(r => {
                    const mapped = mapRecord(r);
                    return {
                        title: mapped.title || "Reference",
                        uri: mapped.uri || "#",
                    };
                })
            };

        case WidgetType.RISK_MATRIX:
            return {
                ...widget,
                risks: records.map(r => {
                    const mapped = mapRecord(r);
                    return {
                        id: mapped.id || r.id,
                        label: mapped.label || "Risk",
                        impact: Number(mapped.impact),
                        likelihood: Number(mapped.likelihood),
                        mitigation: mapped.mitigation
                    };
                })
            };

        case WidgetType.MAP:
            return {
                ...widget,
                markers: records.map(r => {
                    const mapped = mapRecord(r);
                    return {
                        id: mapped.id || r.id,
                        label: mapped.label || "Location",
                        address: mapped.address,
                        latitude: Number(mapped.latitude),
                        longitude: Number(mapped.longitude),
                        description: mapped.description,
                        type: mapped.type
                    };
                })
            };

        case WidgetType.TABLE:
            // For tables, if mapping exists, we use it to construct the view
            const hasMapping = Object.keys(mapping).length > 0;
            // If mapping exists, the headers are the widgetKeys. Otherwise use store schema.
            const headers = hasMapping ? Object.keys(mapping) : Object.keys(store.schema || records[0] || {});

            const tableRows = records.map(r => {
                if (!hasMapping) return r;
                const row: any = {};
                headers.forEach(h => {
                     // For table, keys in mapping are the headers we want to show
                     const col = mapping[h]; 
                     row[h] = r[col];
                });
                return row;
            });

            return {
                ...widget,
                data: {
                    headers: headers,
                    rows: tableRows,
                    columnTypes: {} 
                }
            };

        case WidgetType.CHART:
            const chartData = records;
            const chartConfig = { ...widget.config };

            // Auto-detect dataKeys if missing to prevent "No data keys defined" error
            if (!chartConfig.dataKeys || chartConfig.dataKeys.length === 0) {
                 const potentialKeys = new Set<string>();

                 // Strategy 1: Look at Field Mapping
                 // The UI Agent often maps 'value', 'y', or 'data' to the metric column
                 if (Object.keys(mapping).length > 0) {
                     ['value', 'y', 'data', 'count', 'score', 'metric', 'amount'].forEach(key => {
                         if (mapping[key]) potentialKeys.add(mapping[key]);
                     });
                 }

                 // Strategy 2: Scan Data (Fallback or Supplement)
                 // Scan up to 10 rows to find keys that hold numeric values
                 if (potentialKeys.size === 0) {
                     const xKey = chartConfig.xAxisKey;
                     for (let i = 0; i < Math.min(chartData.length, 10); i++) {
                         const row = chartData[i];
                         if (!row) continue;
                         Object.keys(row).forEach(k => {
                             if (k === 'id' || k === xKey) return;
                             const val = row[k];
                             // Check if number or parsable string (handling potential nulls safely)
                             if (val !== null && val !== undefined && (typeof val === 'number' || (typeof val === 'string' && !isNaN(Number(val))))) {
                                 potentialKeys.add(k);
                             }
                         });
                     }
                 }

                 if (potentialKeys.size > 0) {
                     chartConfig.dataKeys = Array.from(potentialKeys);
                 }
            }

            return {
                ...widget,
                config: chartConfig,
                data: chartData
            };

        case WidgetType.KANBAN:
            // Group By Logic
            const groupBy = (widget.dataSource as any).groupByField || 'status';
            const mappedRecords = records.map(r => mapRecord(r));

            // Get unique groups
            const groups = Array.from(new Set(mappedRecords.map((r: any) => r[groupBy] || 'Uncategorized')));

            const columns = groups.map(group => ({
                id: String(group),
                title: String(group).toUpperCase(),
                tasks: mappedRecords
                    .filter((r: any) => (r[groupBy] || 'Uncategorized') === group)
                    .map((r: any) => ({
                        id: r.id || String(Math.random()),
                        content: r.content || r.title || r.name || r.task || "No Content",
                        tag: r.tag,
                        priority: r.priority,
                        dueDate: r.dueDate
                    }))
            }));

            // Sort Columns by Workflow Status Priority
            columns.sort((a, b) => {
                const idxA = getStatusIndex(a.title);
                const idxB = getStatusIndex(b.title);

                if (idxA !== -1 && idxB !== -1) return idxA - idxB;
                if (idxA !== -1) return -1;
                if (idxB !== -1) return 1;
                return 0; // Maintain default/insertion order if not found
            });

            return {
                ...widget,
                dataSource: {
                    ...widget.dataSource,
                    groupByField: groupBy // Persist the inferred or explicit group by field
                },
                columns
            };

        default:
            return widget;
    }
};


export const WidgetRenderer: React.FC<WidgetRendererProps> = ({ widget, onMindmapNodeClick, isExpanded, projectData, onUpdateRecord }) => {
  // Hydrate the widget data from the store if a dataSource is present
  const hydratedWidget = useMemo(() => {
     if (projectData && projectData.stores && widget.dataSource) {
         return hydrateWidget(widget, projectData.stores);
     }
     return widget;
  }, [widget, projectData]);

  if (!hydratedWidget) return null;

  switch (hydratedWidget.type) {
    case WidgetType.GANTT:
      return <GanttWidget title={hydratedWidget.title} tasks={hydratedWidget.tasks || []} />;
    case WidgetType.CHART:
      return <ChartWidget title={hydratedWidget.title} config={hydratedWidget.config} data={hydratedWidget.data || []} isExpanded={isExpanded} />;
    case WidgetType.KANBAN:
        return (
            <KanbanWidget 
                title={hydratedWidget.title} 
                columns={hydratedWidget.columns || []} 
                isExpanded={isExpanded}
                onTaskMove={(taskId, newStatus) => {
                    const ds = hydratedWidget.dataSource;
                    // Ensure we have a valid group field, defaulting to 'status' if not specified
                    const groupBy = (ds as any).groupByField || 'status';

                    if (onUpdateRecord && ds && ds.storeId) {
                         onUpdateRecord(ds.storeId, taskId, groupBy, newStatus);
                    }
                }}
            />
        );
    case WidgetType.TABLE:
        return <TableWidget title={hydratedWidget.title} data={hydratedWidget.data} />;
    case WidgetType.CODE:
        return <CodeWidget title={hydratedWidget.title} code={hydratedWidget.code} dataContext={projectData} />;
    case WidgetType.MINDMAP:
        return <MindmapWidget title={hydratedWidget.title} nodes={hydratedWidget.nodes} onNodeClick={onMindmapNodeClick} />;
    case WidgetType.METRICS:
        return <MetricsWidget title={hydratedWidget.title} items={hydratedWidget.contentItems || []} />;
    case WidgetType.RISK_MATRIX:
        return <RiskMatrixWidget title={hydratedWidget.title} risks={hydratedWidget.risks || []} />;
    case WidgetType.REFERENCES:
        return <ReferencesWidget title={hydratedWidget.title} items={hydratedWidget.contentItems || []} />;
    case WidgetType.MAP:
        return <MapWidget title={hydratedWidget.title} markers={hydratedWidget.markers || []} />;
    case WidgetType.ERROR:
        return <ErrorWidget title={hydratedWidget.title} error={hydratedWidget.error} />;
    default:
      return null;
  }
};

import React, { useState } from 'react';
import { KanbanColumn } from '../../types';
import { format, parseISO } from 'date-fns';

interface KanbanWidgetProps {
  title: string;
  columns: KanbanColumn[];
  isExpanded?: boolean;
  onTaskMove?: (taskId: string, newColumnId: string) => void;
}

export const KanbanWidget: React.FC<KanbanWidgetProps> = ({ title, columns, isExpanded = false, onTaskMove }) => {
  const [dragOverColumn, setDragOverColumn] = useState<string | null>(null);

  const getPriorityColor = (p?: string) => {
    switch(p) {
      case 'high': return 'bg-red-50 text-red-600 border-red-100';
      case 'medium': return 'bg-amber-50 text-amber-600 border-amber-100';
      case 'low': return 'bg-emerald-50 text-emerald-600 border-emerald-100';
      default: return 'bg-slate-50 text-slate-500 border-slate-100';
    }
  };

  const renderContent = (text: string) => {
    // Regex to split by URLs (http/https)
    const parts = text.split(/(https?:\/\/[^\s]+)/g);
    return (
      <>
        {parts.map((part, i) => {
          if (part.match(/^https?:\/\//)) {
             return (
               <a 
                 key={i} 
                 href={part} 
                 target="_blank" 
                 rel="noopener noreferrer" 
                 className="text-indigo-600 hover:text-indigo-800 hover:underline relative z-20 break-all"
                 onClick={e => e.stopPropagation()}
               >
                 {part}
               </a>
             );
          }
          return <span key={i}>{part}</span>;
        })}
      </>
    );
  };

  const handleDragStart = (e: React.DragEvent, taskId: string) => {
      e.dataTransfer.setData('taskId', taskId);
      e.dataTransfer.effectAllowed = 'move';
      // Make it semitransparent when dragging
      const target = e.target as HTMLElement;
      setTimeout(() => target.classList.add('opacity-50'), 0);
  };

  const handleDragEnd = (e: React.DragEvent) => {
      const target = e.target as HTMLElement;
      target.classList.remove('opacity-50');
      setDragOverColumn(null);
  };

  const handleDragOver = (e: React.DragEvent, colId: string) => {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
      if (dragOverColumn !== colId) {
          setDragOverColumn(colId);
      }
  };

  const handleDrop = (e: React.DragEvent, colId: string) => {
      e.preventDefault();
      e.stopPropagation();
      setDragOverColumn(null);
      const taskId = e.dataTransfer.getData('taskId');
      if (taskId && onTaskMove) {
          onTaskMove(taskId, colId);
      }
  };

  return (
    <div className="w-full bg-slate-50/50 border border-slate-200 rounded-2xl p-6 my-6 overflow-x-auto">
      <h3 className="font-black text-[11px] uppercase tracking-widest text-slate-500 mb-6 flex items-center gap-2 px-1">
        <svg className="w-4 h-4 text-indigo-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 17V7m0 10a2 2 0 01-2 2H5a2 2 0 01-2-2V7a2 2 0 012-2h2a2 2 0 012 2m0 10a2 2 0 002 2h2a2 2 0 002-2M9 7a2 2 0 012-2h2a2 2 0 012 2m0 10V7m0 10a2 2 0 002 2h2a2 2 0 002-2V7a2 2 0 00-2-2h-2a2 2 0 00-2 2" /></svg>
        {title}
      </h3>
      <div className="flex gap-6 min-w-max">
        {columns.map((col) => (
          <div 
            key={col.id} 
            className={`w-72 shrink-0 flex flex-col rounded-2xl p-4 border transition-colors duration-200
                ${dragOverColumn === col.id ? 'bg-indigo-50 border-indigo-300 ring-2 ring-indigo-200' : 'bg-slate-100/50 border-slate-200/50'}
            `}
            onDragOver={(e) => handleDragOver(e, col.id)}
            onDrop={(e) => handleDrop(e, col.id)}
            onDragLeave={() => setDragOverColumn(null)}
          >
            <div className="flex justify-between items-center mb-4 px-1">
                <h4 className="font-black text-[10px] text-slate-600 uppercase tracking-[0.15em]">{col.title}</h4>
                <span className="bg-white text-[10px] font-black text-slate-400 px-2 py-0.5 rounded-full border border-slate-200">{col.tasks.length}</span>
            </div>
            <div className={`flex flex-col gap-3 overflow-y-auto pr-1 transition-all duration-300 min-h-[120px] ${isExpanded ? 'max-h-[750px]' : 'max-h-[500px]'}`}>
              {col.tasks.map((task) => (
                <div 
                    key={task.id} 
                    draggable
                    onDragStart={(e) => handleDragStart(e, task.id)}
                    onDragEnd={handleDragEnd}
                    className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 hover:border-indigo-200 hover:shadow-md transition-all cursor-grab active:cursor-grabbing group select-none"
                >
                  <p className="text-sm font-bold text-slate-800 leading-tight group-hover:text-indigo-700 transition-colors pointer-events-none">
                    {renderContent(task.content)}
                  </p>

                  <div className="mt-4 flex flex-wrap gap-2 items-center pointer-events-none">
                    {task.priority && (
                      <span className={`px-2 py-0.5 rounded-md text-[9px] font-black uppercase tracking-wider border ${getPriorityColor(task.priority)}`}>
                        {task.priority}
                      </span>
                    )}
                    {task.tag && (
                      <span className="px-2 py-0.5 bg-blue-50 text-blue-600 text-[9px] font-black uppercase tracking-wider rounded-md border border-blue-100">
                        {task.tag}
                      </span>
                    )}
                    {task.dueDate && (
                      <div className="ml-auto flex items-center gap-1 text-[9px] font-bold text-slate-400">
                         <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                         {(() => {
                            try { return format(parseISO(task.dueDate), 'MMM d'); }
                            catch (e) { return task.dueDate; }
                         })()}
                      </div>
                    )}
                  </div>
                </div>
              ))}
              {col.tasks.length === 0 && (
                  <div className="flex-1 flex items-center justify-center py-8 text-center text-[10px] font-bold text-slate-300 italic pointer-events-none border-2 border-dashed border-slate-200 rounded-xl">Empty Stage</div>
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { WidgetData, WidgetType, DataStore, DataSourceConfig } from '../types';

interface WidgetEditorModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (widget: WidgetData) => void;
  initialWidget?: WidgetData;
  availableStores: DataStore[];
}

const WIDGET_TYPES = [
  { value: WidgetType.GANTT, label: 'Gantt Chart' },
  { value: WidgetType.CHART, label: 'Chart (Bar/Line/Area)' },
  { value: WidgetType.KANBAN, label: 'Kanban Board' },
  { value: WidgetType.TABLE, label: 'Data Table' },
  { value: WidgetType.METRICS, label: 'Metrics Cards' },
  { value: WidgetType.RISK_MATRIX, label: 'Risk Matrix' },
  { value: WidgetType.MAP, label: 'Map / Locations' },
];

const MAPPING_CONFIG: Record<string, { label: string; key: string; type?: string; required?: boolean }[]> = {
  [WidgetType.GANTT]: [
    { label: 'Task Name', key: 'name', required: true },
    { label: 'Start Date', key: 'start', required: true },
    { label: 'End Date', key: 'end', required: true },
    { label: 'Progress (0-100)', key: 'progress' },
    { label: 'Status', key: 'status' },
    { label: 'Owner', key: 'owner' },
  ],
  [WidgetType.KANBAN]: [
    { label: 'Card Content', key: 'content', required: true },
    { label: 'Group By Column', key: 'groupByField', required: true }, // Special case handling
    { label: 'Tag/Label', key: 'tag' },
    { label: 'Priority', key: 'priority' },
    { label: 'Due Date', key: 'dueDate' },
  ],
  [WidgetType.MAP]: [
    { label: 'Location Name', key: 'label', required: true },
    { label: 'Address', key: 'address' },
    { label: 'Latitude', key: 'latitude' },
    { label: 'Longitude', key: 'longitude' },
    { label: 'Description', key: 'description' },
    { label: 'Type (office/client)', key: 'type' },
  ],
  [WidgetType.RISK_MATRIX]: [
    { label: 'Risk Name', key: 'label', required: true },
    { label: 'Impact (1-5)', key: 'impact', required: true },
    { label: 'Likelihood (1-5)', key: 'likelihood', required: true },
    { label: 'Mitigation', key: 'mitigation' },
  ],
  [WidgetType.METRICS]: [
    { label: 'Label', key: 'label', required: true },
    { label: 'Value', key: 'value', required: true },
    { label: 'Trend (up/down)', key: 'trend' },
    { label: 'Status (good/bad)', key: 'status' },
  ],
  [WidgetType.CHART]: [
    // Special handling for charts
  ],
  [WidgetType.TABLE]: [
      // Table takes all or specific columns, handled separately
  ]
};

export const WidgetEditorModal: React.FC<WidgetEditorModalProps> = ({ isOpen, onClose, onSave, initialWidget, availableStores }) => {
  const [title, setTitle] = useState('');
  const [type, setType] = useState<WidgetType>(WidgetType.GANTT);
  const [selectedStoreId, setSelectedStoreId] = useState<string>('');
  const [mappings, setMappings] = useState<Record<string, string>>({});

  // Chart Specific
  const [chartType, setChartType] = useState<'bar' | 'line' | 'area'>('bar');
  const [xAxis, setXAxis] = useState('');
  const [dataKeys, setDataKeys] = useState<string[]>([]);
  const [chartMultiSelectOpen, setChartMultiSelectOpen] = useState(false);

  useEffect(() => {
    if (isOpen) {
      if (initialWidget) {
        setTitle(initialWidget.title);
        setType(initialWidget.type);
        // Cast to any to handle legacy data structures safely without type errors
        const ds = initialWidget.dataSource as any;
        if (ds) {
          setSelectedStoreId(ds.storeId || '');
          const initialMap: Record<string, string> = {};
          if (Array.isArray(ds.fieldMapping)) {
            ds.fieldMapping.forEach((m: any) => {
                if (m.widgetKey && m.storeColumn) {
                    initialMap[String(m.widgetKey)] = String(m.storeColumn);
                }
            });
          } else if (typeof ds.fieldMapping === 'object') {
             // Legacy support
             Object.assign(initialMap, ds.fieldMapping);
          }

          // Kanban group by special case
          if (ds.groupByField) initialMap['groupByField'] = String(ds.groupByField);

          setMappings(initialMap);
        } else {
            setSelectedStoreId('');
            setMappings({});
        }

        // Chart Config
        if (initialWidget.type === WidgetType.CHART) {
            const chartConfig = (initialWidget as any).config || {};
            setChartType(chartConfig.type || 'bar');
            setXAxis(chartConfig.xAxisKey || '');
            setDataKeys(chartConfig.dataKeys || []);
        }
      } else {
        // Reset for new widget
        setTitle('New Widget');
        setType(WidgetType.GANTT);
        setSelectedStoreId(availableStores[0]?.id || '');
        setMappings({});
        setChartType('bar');
        setXAxis('');
        setDataKeys([]);
      }
    }
  }, [isOpen, initialWidget, availableStores]);

  if (!isOpen) return null;

  const selectedStore = availableStores.find(s => s.id === selectedStoreId);
  const schemaKeys = selectedStore ? Object.keys(selectedStore.schema) : [];

  const handleSave = () => {
    // Construct DataSourceConfig
    const fieldMapping: { widgetKey: string, storeColumn: string }[] = [];
    let groupByField: string | undefined = undefined;

    Object.entries(mappings).forEach(([wKey, sCol]) => {
        if (!sCol) return;
        if (wKey === 'groupByField') {
            groupByField = sCol;
        } else {
            fieldMapping.push({ widgetKey: wKey, storeColumn: sCol });
        }
    });

    const dataSource: any = selectedStoreId ? {
        storeId: selectedStoreId,
        fieldMapping,
        groupByField
    } : undefined;

    const widget: any = {
        // Preserve other data if editing
        ...(initialWidget ? { ...initialWidget } : {}),
        type,
        title,
        dataSource,
    };

    // Clean up hardcoded data if switching to data source
    if (dataSource) {
        if (type === WidgetType.GANTT) widget.tasks = undefined;
        if (type === WidgetType.KANBAN) widget.columns = undefined;
        if (type === WidgetType.TABLE) widget.data = undefined;
        if (type === WidgetType.CHART) widget.data = undefined;
        if (type === WidgetType.METRICS) widget.contentItems = undefined;
        if (type === WidgetType.RISK_MATRIX) widget.risks = undefined;
        if (type === WidgetType.MAP) widget.markers = undefined;
    }

    // Add Chart Config
    if (type === WidgetType.CHART) {
        widget.config = {
            type: chartType,
            xAxisKey: xAxis,
            dataKeys: dataKeys,
            title,
            colors: ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6']
        };
    }

    onSave(widget);
    onClose();
  };

  const renderMappingInputs = () => {
      const config = MAPPING_CONFIG[type];
      if (!config) return null;

      return (
          <div className="space-y-3 mt-4">
              <div className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Map Data Fields</div>
              {config.map(field => (
                  <div key={field.key} className="flex items-center justify-between">
                      <label className="text-sm font-medium text-slate-700 w-1/3">
                          {field.label}
                          {field.required && <span className="text-red-500">*</span>}
                      </label>
                      <select 
                        className="flex-1 p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm"
                        value={mappings[field.key] || ''}
                        onChange={e => setMappings(prev => ({ ...prev, [field.key]: e.target.value }))}
                      >
                          <option value="">-- Select Field --</option>
                          {schemaKeys.map(k => (
                              <option key={k} value={k}>{k}</option>
                          ))}
                      </select>
                  </div>
              ))}
          </div>
      );
  };

  const renderChartConfig = () => {
      if (type !== WidgetType.CHART) return null;
      return (
        <div className="space-y-3 mt-4">
            <div className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Chart Configuration</div>

            <div className="flex items-center justify-between">
                <label className="text-sm font-medium text-slate-700 w-1/3">Chart Type</label>
                <div className="flex-1 flex gap-2">
                    {['bar', 'line', 'area'].map(t => (
                        <button 
                            key={t}
                            onClick={() => setChartType(t as any)}
                            className={`px-3 py-1.5 rounded-lg text-xs font-bold uppercase ${chartType === t ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-500'}`}
                        >
                            {t}
                        </button>
                    ))}
                </div>
            </div>

            <div className="flex items-center justify-between">
                <label className="text-sm font-medium text-slate-700 w-1/3">X-Axis Field</label>
                <select 
                    className="flex-1 p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm"
                    value={xAxis}
                    onChange={e => setXAxis(e.target.value)}
                >
                    <option value="">-- Select Field --</option>
                    {schemaKeys.map(k => (
                        <option key={k} value={k}>{k}</option>
                    ))}
                </select>
            </div>

            <div className="flex items-start justify-between relative">
                <label className="text-sm font-medium text-slate-700 w-1/3 mt-2">Data Keys (Y-Axis)</label>
                <div className="flex-1">
                    <div 
                        className="p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm min-h-[38px] cursor-pointer flex flex-wrap gap-1"
                        onClick={() => setChartMultiSelectOpen(!chartMultiSelectOpen)}
                    >
                        {dataKeys.length === 0 && <span className="text-slate-400">Select columns...</span>}
                        {dataKeys.map(k => (
                            <span key={k} className="px-1.5 py-0.5 bg-indigo-100 text-indigo-700 rounded text-xs font-bold flex items-center gap-1">
                                {k}
                                <span className="hover:text-red-500" onClick={(e) => {
                                    e.stopPropagation();
                                    setDataKeys(prev => prev.filter(p => p !== k));
                                }}>×</span>
                            </span>
                        ))}
                    </div>
                    {chartMultiSelectOpen && (
                        <div className="absolute top-full left-[33.33%] right-0 mt-1 bg-white border border-slate-200 rounded-lg shadow-xl z-50 max-h-48 overflow-y-auto p-1">
                            {schemaKeys.map(k => (
                                <div 
                                    key={k} 
                                    className={`px-3 py-2 text-sm rounded cursor-pointer hover:bg-slate-50 flex items-center gap-2 ${dataKeys.includes(k) ? 'font-bold text-indigo-600' : 'text-slate-700'}`}
                                    onClick={() => {
                                        if (dataKeys.includes(k)) setDataKeys(prev => prev.filter(p => p !== k));
                                        else setDataKeys(prev => [...prev, k]);
                                    }}
                                >
                                    <div className={`w-4 h-4 rounded border flex items-center justify-center ${dataKeys.includes(k) ? 'bg-indigo-600 border-indigo-600 text-white' : 'border-slate-300'}`}>
                                        {dataKeys.includes(k) && <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>}
                                    </div>
                                    {k}
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>
        </div>
      );
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200" onClick={onClose}>
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg p-6 animate-in zoom-in-95 duration-200 max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
        <div className="flex items-center justify-between mb-6">
            <h3 className="text-lg font-bold text-slate-900">
                {initialWidget ? 'Edit Widget' : 'Add New Widget'}
            </h3>
            <button onClick={onClose} className="p-1.5 hover:bg-slate-100 rounded-lg text-slate-400">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
        </div>

        <div className="space-y-5">
            <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1.5">Widget Title</label>
                <input 
                    type="text" 
                    value={title}
                    onChange={e => setTitle(e.target.value)}
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500"
                    placeholder="e.g., Project Timeline"
                />
            </div>

            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1.5">Widget Type</label>
                    <select 
                        value={type}
                        onChange={e => setType(e.target.value as WidgetType)}
                        className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500"
                    >
                        {WIDGET_TYPES.map(t => (
                            <option key={t.value} value={t.value}>{t.label}</option>
                        ))}
                    </select>
                </div>
                <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1.5">Data Source</label>
                    <select 
                        value={selectedStoreId}
                        onChange={e => {
                            setSelectedStoreId(e.target.value);
                            setMappings({}); // Reset mappings on store change
                        }}
                        className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500"
                    >
                        <option value="">No Source (Static)</option>
                        {availableStores.map(s => (
                            <option key={s.id} value={s.id}>{s.name}</option>
                        ))}
                    </select>
                </div>
            </div>

            {selectedStoreId && (
                <div className="bg-indigo-50/50 rounded-xl p-4 border border-indigo-100">
                    {renderMappingInputs()}
                    {renderChartConfig()}
                </div>
            )}

            {!selectedStoreId && (
                <div className="p-4 bg-amber-50 border border-amber-100 rounded-xl text-xs text-amber-700">
                    <b>Note:</b> Without a data source, this widget will display static data or be empty. Connect a Data Store to make it dynamic.
                </div>
            )}

            <div className="pt-4 flex gap-3">
                <button 
                    onClick={onClose}
                    className="flex-1 py-3 text-sm font-bold text-slate-500 hover:bg-slate-50 rounded-xl transition-colors"
                >
                    Cancel
                </button>
                <button 
                    onClick={handleSave}
                    className="flex-1 py-3 bg-indigo-600 text-white text-sm font-bold rounded-xl shadow-lg shadow-indigo-200 hover:bg-indigo-700 transition-all"
                >
                    Save Widget
                </button>
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useMemo } from 'react';
import { WidgetData, WidgetType, MindmapNode, DataStore } from '../../types';
import { GanttWidget } from './GanttWidget';
import { ChartWidget } from './ChartWidget';
import { KanbanWidget } from './KanbanWidget';
import { MindmapWidget } from './MindmapWidget';
import { MapWidget } from './MapWidget';
import { MetricsWidget } from './MetricsWidget';
import { RiskMatrixWidget } from './RiskMatrixWidget';
import { ReferencesWidget } from './ReferencesWidget';
import { ErrorWidget } from './ErrorWidget';
import { CodeWidget } from './CodeWidget';
import { TableWidget } from './TableWidget';

interface WidgetRendererProps {
  widget: WidgetData;
  onMindmapNodeClick?: (node: MindmapNode) => void;
  isExpanded?: boolean;
  projectData?: { stores: DataStore[] }; // Pass the full project data context
  onUpdateRecord?: (storeId: string, recordId: string, field: string, value: any) => void;
}

// --- HYDRATION HELPERS ---

const STATUS_PRIORITY = [
  'backlog', 'todo', 'to do', 'planned', 'open', 'new',
  'in-progress', 'in progress', 'active', 'doing', 'wip', 'developing',
  'review', 'qa', 'testing', 'verify', 'verification',
  'blocked', 'holding', 'on-hold',
  'done', 'completed', 'closed', 'released', 'shipped'
];

const getStatusIndex = (title: string) => {
  const normalized = title.toLowerCase().trim();
  const idx = STATUS_PRIORITY.indexOf(normalized);
  if (idx !== -1) return idx;
  // Try partial match
  return STATUS_PRIORITY.findIndex(s => normalized.includes(s));
};

const hydrateWidget = (widget: WidgetData, stores: DataStore[]): any => {
    // If no data source or invalid data source, return widget as is (Legacy mode)
    if (!widget.dataSource || !widget.dataSource.storeId) return widget;

    const store = stores.find(s => s.id === widget.dataSource!.storeId);
    if (!store) {
        console.warn(`Widget ${widget.title} referenced missing store: ${widget.dataSource!.storeId}`);
        return widget;
    }

    // Convert array-based mapping to Record<widgetKey, storeColumn>
    const mappingArray = widget.dataSource!.fieldMapping || [];
    const mapping: Record<string, string> = {};
    if (Array.isArray(mappingArray)) {
        mappingArray.forEach(m => {
            if (m.widgetKey && m.storeColumn) {
                mapping[m.widgetKey] = m.storeColumn;
            }
        });
    } else {
        // Fallback for single object or legacy map
        const asObj = mappingArray as any;
        if (asObj.widgetKey && asObj.storeColumn) {
             mapping[asObj.widgetKey] = asObj.storeColumn;
        } else {
             Object.assign(mapping, mappingArray);
        }
    }

    const records = store.records || [];

    // Helper to map a record using the field mapping
    const mapRecord = (record: any) => {
        const result: any = { ...record }; // Keep original fields for flexibility
        Object.entries(mapping).forEach(([widgetKey, storeColumn]) => {
            if (storeColumn && record[storeColumn] !== undefined) {
                result[widgetKey] = record[storeColumn];
            }
        });
        return result;
    };

    switch (widget.type) {
        case WidgetType.GANTT:
            return {
                ...widget,
                tasks: records.map(r => {
                    const mapped = mapRecord(r);

                    // Robust fallback logic for common fields if mapping misses them
                    // This handles cases where models use keys like 'start_date' but don't map them to 'start'
                    const findVal = (keys: string[]) => {
                        for (const k of keys) {
                            if (mapped[k] !== undefined && mapped[k] !== null) return mapped[k];
                        }
                        // Case-insensitive fallback
                        const lowerKeys = keys.map(k => k.toLowerCase());
                        for (const k of Object.keys(mapped)) {
                             if (lowerKeys.includes(k.toLowerCase()) && mapped[k] !== undefined && mapped[k] !== null) return mapped[k];
                        }
                        return undefined;
                    };

                    const name = mapped.name || findVal(['task', 'title', 'label', 'content', 'item', 'feature']) || "Untitled Task";
                    const start = mapped.start || findVal(['start_date', 'startDate', 'begin', 'init', 'created_at']);
                    const end = mapped.end || findVal(['end_date', 'endDate', 'finish', 'due', 'dueDate', 'deadline', 'target_date']);
                    const progress = mapped.progress !== undefined ? mapped.progress : findVal(['percent', 'percentage', 'completion', 'done']);
                    const status = mapped.status || findVal(['state', 'stage']);
                    const owner = mapped.owner || findVal(['assignee', 'user', 'who', 'lead']);

                    return {
                        id: mapped.id || r.id || String(Math.random()),
                        name: String(name),
                        start: start,
                        end: end,
                        progress: progress ? Number(progress) : 0,
                        owner: owner,
                        status: status,
                        isEstimated: mapped.isEstimated,
                        dependencies: mapped.dependencies
                    };
                })
            };

        case WidgetType.METRICS:
            return {
                ...widget,
                contentItems: records.map(r => {
                    const mapped = mapRecord(r);
                    return {
                        label: mapped.label || "Metric",
                        value: mapped.value,
                        trend: mapped.trend,
                        status: mapped.status,
                        description: mapped.description
                    };
                })
            };

        case WidgetType.REFERENCES:
            return {
                ...widget,
                contentItems: records.map(r => {
                    const mapped = mapRecord(r);
                    return {
                        title: mapped.title || "Reference",
                        uri: mapped.uri || "#",
                    };
                })
            };

        case WidgetType.RISK_MATRIX:
            return {
                ...widget,
                risks: records.map(r => {
                    const mapped = mapRecord(r);
                    return {
                        id: mapped.id || r.id,
                        label: mapped.label || "Risk",
                        impact: Number(mapped.impact),
                        likelihood: Number(mapped.likelihood),
                        mitigation: mapped.mitigation
                    };
                })
            };

        case WidgetType.MAP:
            return {
                ...widget,
                markers: records.map(r => {
                    const mapped = mapRecord(r);
                    return {
                        id: mapped.id || r.id,
                        label: mapped.label || "Location",
                        address: mapped.address,
                        latitude: Number(mapped.latitude),
                        longitude: Number(mapped.longitude),
                        description: mapped.description,
                        type: mapped.type
                    };
                })
            };

        case WidgetType.TABLE:
            // For tables, if mapping exists, we use it to construct the view
            const hasMapping = Object.keys(mapping).length > 0;
            // If mapping exists, the headers are the widgetKeys. Otherwise use store schema.
            const headers = hasMapping ? Object.keys(mapping) : Object.keys(store.schema || records[0] || {});

            const tableRows = records.map(r => {
                if (!hasMapping) return r;
                const row: any = {};
                headers.forEach(h => {
                     // For table, keys in mapping are the headers we want to show
                     const col = mapping[h]; 
                     row[h] = r[col];
                });
                return row;
            });

            return {
                ...widget,
                data: {
                    headers: headers,
                    rows: tableRows,
                    columnTypes: {} 
                }
            };

        case WidgetType.CHART:
            const chartData = records;
            const chartConfig = { ...widget.config };

            // Auto-detect dataKeys if missing to prevent "No data keys defined" error
            if (!chartConfig.dataKeys || chartConfig.dataKeys.length === 0) {
                 const potentialKeys = new Set<string>();

                 // Strategy 1: Look at Field Mapping
                 // The UI Agent often maps 'value', 'y', or 'data' to the metric column
                 if (Object.keys(mapping).length > 0) {
                     ['value', 'y', 'data', 'count', 'score', 'metric', 'amount'].forEach(key => {
                         if (mapping[key]) potentialKeys.add(mapping[key]);
                     });
                 }

                 // Strategy 2: Scan Data (Fallback or Supplement)
                 // Scan up to 10 rows to find keys that hold numeric values
                 if (potentialKeys.size === 0) {
                     const xKey = chartConfig.xAxisKey;
                     for (let i = 0; i < Math.min(chartData.length, 10); i++) {
                         const row = chartData[i];
                         if (!row) continue;
                         Object.keys(row).forEach(k => {
                             if (k === 'id' || k === xKey) return;
                             const val = row[k];
                             // Check if number or parsable string (handling potential nulls safely)
                             if (val !== null && val !== undefined && (typeof val === 'number' || (typeof val === 'string' && !isNaN(Number(val))))) {
                                 potentialKeys.add(k);
                             }
                         });
                     }
                 }

                 if (potentialKeys.size > 0) {
                     chartConfig.dataKeys = Array.from(potentialKeys);
                 }
            }

            return {
                ...widget,
                config: chartConfig,
                data: chartData
            };

        case WidgetType.KANBAN:
            // Group By Logic
            const groupBy = (widget.dataSource as any).groupByField || 'status';
            const mappedRecords = records.map(r => mapRecord(r));

            // Initialize groups set
            const groupsSet = new Set<string>();

            // 1. Respect existing columns defined in the widget (visual structure)
            if (widget.columns && Array.isArray(widget.columns)) {
                widget.columns.forEach(c => {
                    if (c.title) groupsSet.add(c.title);
                });
            }

            // 2. Add groups found in data
            mappedRecords.forEach((r: any) => {
                 const val = r[groupBy];
                 groupsSet.add(val !== undefined && val !== null ? String(val) : 'Uncategorized');
            });

            // 3. Fallback Heuristics: Ensure standard columns exist if grouping by status or priority
            const lowerGroupField = groupBy.toLowerCase();
            const hasGroup = (g: string) => {
                for (let existing of groupsSet) {
                    if (existing.toLowerCase() === g.toLowerCase()) return true;
                }
                return false;
            };

            if (lowerGroupField.includes('status') || lowerGroupField.includes('state') || lowerGroupField.includes('stage')) {
                if (!hasGroup('Todo') && !hasGroup('To Do') && !hasGroup('Backlog')) groupsSet.add('Todo');
                if (!hasGroup('In Progress') && !hasGroup('In-Progress') && !hasGroup('Doing') && !hasGroup('Active')) groupsSet.add('In Progress');
                if (!hasGroup('Done') && !hasGroup('Completed')) groupsSet.add('Done');
            }

            if (lowerGroupField.includes('priority')) {
                 if (!hasGroup('High') && !hasGroup('Critical')) groupsSet.add('High');
                 if (!hasGroup('Medium')) groupsSet.add('Medium');
                 if (!hasGroup('Low')) groupsSet.add('Low');
            }

            const groups = Array.from(groupsSet);

            const columns = groups.map(group => {
                // Try to find existing column config to preserve ID/Title casing preference
                const existingCol = widget.columns?.find(c => c.title.toLowerCase() === group.toLowerCase() || c.id === group);

                const title = existingCol?.title || group;
                const id = existingCol?.id || group;

                return {
                    id: id,
                    title: title.toUpperCase(),
                    tasks: mappedRecords
                        .filter((r: any) => {
                             const val = r[groupBy];
                             const rGroup = val !== undefined && val !== null ? String(val) : 'Uncategorized';
                             return rGroup.toLowerCase() === group.toLowerCase(); 
                        })
                        .map((r: any) => ({
                            id: r.id || String(Math.random()),
                            content: r.content || r.title || r.name || r.task || "No Content",
                            tag: r.tag,
                            priority: r.priority,
                            dueDate: r.dueDate
                        }))
                };
            });

            // Sort Columns by Workflow Status Priority
            columns.sort((a, b) => {
                const idxA = getStatusIndex(a.title);
                const idxB = getStatusIndex(b.title);

                if (idxA !== -1 && idxB !== -1) return idxA - idxB;
                if (idxA !== -1) return -1;
                if (idxB !== -1) return 1;
                return 0; // Maintain default/insertion order if not found
            });

            return {
                ...widget,
                dataSource: {
                    ...widget.dataSource,
                    groupByField: groupBy // Persist the inferred or explicit group by field
                },
                columns
            };

        default:
            return widget;
    }
};


export const WidgetRenderer: React.FC<WidgetRendererProps> = ({ widget, onMindmapNodeClick, isExpanded, projectData, onUpdateRecord }) => {
  // Hydrate the widget data from the store if a dataSource is present
  const hydratedWidget = useMemo(() => {
     if (projectData && projectData.stores && widget.dataSource) {
         return hydrateWidget(widget, projectData.stores);
     }
     return widget;
  }, [widget, projectData]);

  if (!hydratedWidget) return null;

  switch (hydratedWidget.type) {
    case WidgetType.GANTT:
      return <GanttWidget title={hydratedWidget.title} tasks={hydratedWidget.tasks || []} />;
    case WidgetType.CHART:
      return <ChartWidget title={hydratedWidget.title} config={hydratedWidget.config} data={hydratedWidget.data || []} isExpanded={isExpanded} />;
    case WidgetType.KANBAN:
        return (
            <KanbanWidget 
                title={hydratedWidget.title} 
                columns={hydratedWidget.columns || []} 
                isExpanded={isExpanded}
                onTaskMove={(taskId, newStatus) => {
                    const ds = hydratedWidget.dataSource;
                    // Ensure we have a valid group field, defaulting to 'status' if not specified
                    const groupBy = (ds as any).groupByField || 'status';

                    if (onUpdateRecord && ds && ds.storeId) {
                         onUpdateRecord(ds.storeId, taskId, groupBy, newStatus);
                    }
                }}
            />
        );
    case WidgetType.TABLE:
        return <TableWidget title={hydratedWidget.title} data={hydratedWidget.data} />;
    case WidgetType.CODE:
        return <CodeWidget title={hydratedWidget.title} code={hydratedWidget.code} dataContext={projectData} />;
    case WidgetType.MINDMAP:
        return <MindmapWidget title={hydratedWidget.title} nodes={hydratedWidget.nodes} onNodeClick={onMindmapNodeClick} />;
    case WidgetType.METRICS:
        return <MetricsWidget title={hydratedWidget.title} items={hydratedWidget.contentItems || []} />;
    case WidgetType.RISK_MATRIX:
        return <RiskMatrixWidget title={hydratedWidget.title} risks={hydratedWidget.risks || []} />;
    case WidgetType.REFERENCES:
        return <ReferencesWidget title={hydratedWidget.title} items={hydratedWidget.contentItems || []} />;
    case WidgetType.MAP:
        return <MapWidget title={hydratedWidget.title} markers={hydratedWidget.markers || []} />;
    case WidgetType.ERROR:
        return <ErrorWidget title={hydratedWidget.title} error={hydratedWidget.error} />;
    default:
      return null;
  }
};

