const MAPPING_CONFIG: Record<string, { label: string; key: string; type?: string; required?: boolean }[]> = {
  [WidgetType.GANTT]: [
    { label: 'Task Name', key: 'name', required: true },
    { label: 'Start Date', key: 'start', required: true },
