  ],
  [WidgetType.CHART]: [
    // Special handling for charts
  ],
  [WidgetType.TABLE]: [
      // Table takes all or specific columns, handled separately
  ]
};

export const WidgetEditorModal: React.FC<WidgetEditorModalProps> = ({ isOpen, onClose, onSave, initialWidget, availableStores }) => {
  const [title, setTitle] = useState('');
  const [type, setType] = useState<WidgetType>(WidgetType.GANTT);
  const [selectedStoreId, setSelectedStoreId] = useState<string>('');
  const [mappings, setMappings] = useState<Record<string, string>>({});

  // Chart Specific
  const [chartType, setChartType] = useState<'bar' | 'line' | 'area'>('bar');
  const [xAxis, setXAxis] = useState('');
  const [dataKeys, setDataKeys] = useState<string[]>([]);
  const [chartMultiSelectOpen, setChartMultiSelectOpen] = useState(false);

  useEffect(() => {
    if (isOpen) {
      if (initialWidget) {
        setTitle(initialWidget.title);
        setType(initialWidget.type);
        // Cast to any to handle legacy data structures safely without type errors
        const ds = initialWidget.dataSource as any;
        if (ds) {
          setSelectedStoreId(ds.storeId || '');
          const initialMap: Record<string, string> = {};
          if (Array.isArray(ds.fieldMapping)) {
            ds.fieldMapping.forEach((m: any) => {
                if (m.widgetKey && m.storeColumn) {
                    initialMap[String(m.widgetKey)] = String(m.storeColumn);
                }
            });
          } else if (typeof ds.fieldMapping === 'object') {
             // Legacy support
             Object.assign(initialMap, ds.fieldMapping);
          }

          // Kanban group by special case
          if (ds.groupByField) initialMap['groupByField'] = String(ds.groupByField);

          setMappings(initialMap);
        } else {
            setSelectedStoreId('');
            setMappings({});
        }

        // Chart Config
        if (initialWidget.type === WidgetType.CHART) {
            const chartConfig = (initialWidget as any).config || {};
            setChartType((chartConfig.type as 'bar' | 'line' | 'area') || 'bar');
            setXAxis(String(chartConfig.xAxisKey || ''));
            const dKeys = chartConfig.dataKeys;
            setDataKeys(Array.isArray(dKeys) ? (dKeys as string[]) : []);
        }
      } else {
        // Reset for new widget
        setTitle('New Widget');
        setType(WidgetType.GANTT);
        setSelectedStoreId(availableStores[0]?.id || '');
        setMappings({});
        setChartType('bar');
        setXAxis('');
        setDataKeys([]);
      }
    }
  }, [isOpen, initialWidget, availableStores]);

  if (!isOpen) return null;

  const selectedStore = availableStores.find(s => s.id === selectedStoreId);
  const schemaKeys = selectedStore ? Object.keys(selectedStore.schema) : [];

  const handleSave = () => {
    // Construct DataSourceConfig
    const fieldMapping: { widgetKey: string, storeColumn: string }[] = [];
    let groupByField: string | undefined = undefined;

    Object.entries(mappings).forEach(([wKey, sCol]) => {
        if (!sCol) return;
        if (wKey === 'groupByField') {
            groupByField = sCol;
        } else {
            fieldMapping.push({ widgetKey: wKey, storeColumn: sCol });
        }
    });

    const dataSource: any = selectedStoreId ? {
        storeId: selectedStoreId,
        fieldMapping,
        groupByField
    } : undefined;

    const widget: any = {
        // Preserve other data if editing
        ...(initialWidget ? { ...initialWidget } : {}),
        type,
        title,
        dataSource,
    };

    // Clean up hardcoded data if switching to data source
    if (dataSource) {
        if (type === WidgetType.GANTT) widget.tasks = undefined;
        if (type === WidgetType.KANBAN) widget.columns = undefined;
        if (type === WidgetType.TABLE) widget.data = undefined;
        if (type === WidgetType.CHART) widget.data = undefined;
        if (type === WidgetType.METRICS) widget.contentItems = undefined;
        if (type === WidgetType.RISK_MATRIX) widget.risks = undefined;
        if (type === WidgetType.MAP) widget.markers = undefined;
    }

    // Add Chart Config
    if (type === WidgetType.CHART) {
        widget.config = {
            type: chartType,
            xAxisKey: xAxis,
            dataKeys: dataKeys,
            title,
            colors: ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6']
        };
    }

    onSave(widget);
    onClose();
  };

  const renderMappingInputs = () => {
      const config = MAPPING_CONFIG[type];
      if (!config) return null;

      return (
          <div className="space-y-3 mt-4">
              <div className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Map Data Fields</div>
              {config.map(field => (
                  <div key={field.key} className="flex items-center justify-between">
                      <label className="text-sm font-medium text-slate-700 w-1/3">
                          {field.label}
                          {field.required && <span className="text-red-500">*</span>}
                      </label>
                      <select 
                        className="flex-1 p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm"
                        value={mappings[field.key] || ''}
                        onChange={e => setMappings(prev => ({ ...prev, [field.key]: e.target.value }))}
                      >
                          <option value="">-- Select Field --</option>
                          {schemaKeys.map(k => (
                              <option key={k} value={k}>{k}</option>
                          ))}
                      </select>
                  </div>
              ))}
          </div>
      );
  };

  const renderChartConfig = () => {
      if (type !== WidgetType.CHART) return null;
      return (
        <div className="space-y-3 mt-4">
            <div className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Chart Configuration</div>

            <div className="flex items-center justify-between">
                <label className="text-sm font-medium text-slate-700 w-1/3">Chart Type</label>
                <div className="flex-1 flex gap-2">
                    {['bar', 'line', 'area'].map(t => (
                        <button 
                            key={t}
                            onClick={() => setChartType(t as any)}
                            className={`px-3 py-1.5 rounded-lg text-xs font-bold uppercase ${chartType === t ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-500'}`}
                        >
                            {t}
                        </button>
                    ))}
                </div>
            </div>

            <div className="flex items-center justify-between">
                <label className="text-sm font-medium text-slate-700 w-1/3">X-Axis Field</label>
                <select 
                    className="flex-1 p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm"
                    value={xAxis}
                    onChange={e => setXAxis(e.target.value)}
                >
                    <option value="">-- Select Field --</option>
                    {schemaKeys.map(k => (
                        <option key={k} value={k}>{k}</option>
                    ))}
                </select>
            </div>

            <div className="flex items-start justify-between relative">
                <label className="text-sm font-medium text-slate-700 w-1/3 mt-2">Data Keys (Y-Axis)</label>
                <div className="flex-1">
                    <div 
                        className="p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm min-h-[38px] cursor-pointer flex flex-wrap gap-1"
                        onClick={() => setChartMultiSelectOpen(!chartMultiSelectOpen)}
                    >
                        {dataKeys.length === 0 && <span className="text-slate-400">Select columns...</span>}
                        {dataKeys.map(k => (
                            <span key={k} className="px-1.5 py-0.5 bg-indigo-100 text-indigo-700 rounded text-xs font-bold flex items-center gap-1">
                                {k}
                                <span className="hover:text-red-500" onClick={(e) => {
                                    e.stopPropagation();
                                    setDataKeys(prev => prev.filter(p => p !== k));
                                }}>×</span>
                            </span>
                        ))}
                    </div>
                    {chartMultiSelectOpen && (
                        <div className="absolute top-full left-[33.33%] right-0 mt-1 bg-white border border-slate-200 rounded-lg shadow-xl z-50 max-h-48 overflow-y-auto p-1">
                            {schemaKeys.map(k => (
                                <div 
                                    key={k} 
                                    className={`px-3 py-2 text-sm rounded cursor-pointer hover:bg-slate-50 flex items-center gap-2 ${dataKeys.includes(k) ? 'font-bold text-indigo-600' : 'text-slate-700'}`}
                                    onClick={() => {
                                        if (dataKeys.includes(k)) setDataKeys(prev => prev.filter(p => p !== k));
                                        else setDataKeys(prev => [...prev, k]);
                                    }}
                                >
                                    <div className={`w-4 h-4 rounded border flex items-center justify-center ${dataKeys.includes(k) ? 'bg-indigo-600 border-indigo-600 text-white' : 'border-slate-300'}`}>
                                        {dataKeys.includes(k) && <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>}
                                    </div>
                                    {k}
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>
        </div>
      );
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200" onClick={onClose}>
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg p-6 animate-in zoom-in-95 duration-200 max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
        <div className="flex items-center justify-between mb-6">
            <h3 className="text-lg font-bold text-slate-900">
                {initialWidget ? 'Edit Widget' : 'Add New Widget'}
            </h3>
            <button onClick={onClose} className="p-1.5 hover:bg-slate-100 rounded-lg text-slate-400">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
        </div>

        <div className="space-y-5">
            <div>
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1.5">Widget Title</label>
                <input 
                    type="text" 
                    value={title}
                    onChange={e => setTitle(e.target.value)}
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500"
                    placeholder="e.g., Project Timeline"
                />
            </div>

            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1.5">Widget Type</label>
                    <select 
                        value={type}
                        onChange={e => setType(e.target.value as WidgetType)}
                        className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500"
                    >
                        {WIDGET_TYPES.map(t => (
                            <option key={t.value} value={t.value}>{t.label}</option>
                        ))}
                    </select>
                </div>
                <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1.5">Data Source</label>
                    <select 
                        value={selectedStoreId}
                        onChange={e => {
                            setSelectedStoreId(e.target.value);
                            setMappings({}); // Reset mappings on store change
                        }}
                        className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500"
                    >
                        <option value="">No Source (Static)</option>
                        {availableStores.map(s => (
                            <option key={s.id} value={s.id}>{s.name}</option>
                        ))}
                    </select>
                </div>
            </div>

            {selectedStoreId && (
                <div className="bg-indigo-50/50 rounded-xl p-4 border border-indigo-100">
                    {renderMappingInputs()}
                    {renderChartConfig()}
                </div>
            )}

            {!selectedStoreId && (
                <div className="p-4 bg-amber-50 border border-amber-100 rounded-xl text-xs text-amber-700">
                    <b>Note:</b> Without a data source, this widget will display static data or be empty. Connect a Data Store to make it dynamic.
                </div>
            )}

            <div className="pt-4 flex gap-3">
                <button 
                    onClick={onClose}
                    className="flex-1 py-3 text-sm font-bold text-slate-500 hover:bg-slate-50 rounded-xl transition-colors"
                >
                    Cancel
                </button>
                <button 
                    onClick={handleSave}
                    className="flex-1 py-3 bg-indigo-600 text-white text-sm font-bold rounded-xl shadow-lg shadow-indigo-200 hover:bg-indigo-700 transition-all"
                >
                    Save Widget
                </button>
            </div>
        </div>
      </div>
    </div>
  );
};

// ... existing imports
import React, { useState, useEffect, useRef } from 'react';
import { ProjectNode, ProjectState, MindmapNode, NodeVisualization, NodeData, WidgetData } from '../types';
import { WidgetRenderer } from './GenerativeUI/WidgetRenderer';
import { DebugOverlay } from './DebugOverlay';
import { ChatTurn } from './ChatTurn';
import { ProjectKnowledgeCard } from './ProjectKnowledgeCard';
import { DataStoreExplorer } from './DataStoreExplorer';
import { SynthesisModal } from './SynthesisModal';
import { ConfirmationModal } from './ConfirmationModal';
import { NodeHeader } from './Layout/NodeHeader';
import { SnapshotBanner } from './Layout/SnapshotBanner';
import { WidgetEditorModal } from './WidgetEditorModal';

interface NodeViewProps {
  node: ProjectNode;
  parentNode?: ProjectNode;
  projectState: ProjectState;
  onSelectNode: (id: string) => void;
  onRegenerate: (input: string) => void;
  onSynthesize: (topic?: string) => void;
  onRefresh: () => void;
  onMindmapNodeClick?: (node: MindmapNode) => void;
  onDeleteChatMessage?: (index: number) => void;
  onDeleteWidget: (nodeId: string, index: number) => void;
  onToggleSidebar: () => void;
  isSidebarOpen: boolean;
  onUpdateNodeData: (nodeId: string, data: any) => void;
  onUpdateNodeViz?: (nodeId: string, viz: any) => void;
  onRevertState: (index: number) => void;
  onShowCleanupModal: () => void;
  onUndoCleanup?: () => void;
}

export const NodeView: React.FC<NodeViewProps> = ({ 
  node, 
  parentNode, 
  projectState, 
  onSelectNode, 
  onRegenerate, 
  onSynthesize, 
  onRefresh,
  onMindmapNodeClick,
  onDeleteChatMessage,
  onDeleteWidget,
  onToggleSidebar,
  isSidebarOpen,
  onUpdateNodeData,
  onUpdateNodeViz,
  onRevertState,
  onShowCleanupModal,
  onUndoCleanup
}) => {
  const [selectedImage, setSelectedImage] = useState<{data: string, name: string} | null>(null);
  const [showDebug, setShowDebug] = useState(false);
  const [showDataExplorer, setShowDataExplorer] = useState(false);
  const [showSynthesisModal, setShowSynthesisModal] = useState(false);
  const [vizMode, setVizMode] = useState<'minimized' | 'normal' | 'large' | 'maximized'>('normal');
  const [showVizDetails, setShowVizDetails] = useState(true);
  const scrollEndRef = useRef<HTMLDivElement>(null);

  const [viewingSnapshot, setViewingSnapshot] = useState<{data: NodeData, viz: NodeVisualization, index: number} | null>(null);
  const [confirmRevertIndex, setConfirmRevertIndex] = useState<number | null>(null);

  // Widget Editor State
  const [widgetEditorOpen, setWidgetEditorOpen] = useState(false);
  const [editingWidgetIndex, setEditingWidgetIndex] = useState<number | null>(null);

  useEffect(() => {
    setViewingSnapshot(null);
    setConfirmRevertIndex(null);
  }, [node.id]);

  useEffect(() => {
    scrollEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [node.chat, node.isLoading, node.id, node.processingStage, viewingSnapshot]);

  const allNodes = (Object.values(projectState.nodes) as ProjectNode[]).sort((a, b) => a.timestamp - b.timestamp);
  const currentIndex = allNodes.findIndex(n => n.id === node.id);

  const handleDownload = (data: string, filename: string) => {
    const link = document.createElement('a');
    link.href = data;
    link.download = filename;
    link.click();
  };

  const handleSaveWidget = (updatedWidget: WidgetData) => {
    if (!onUpdateNodeViz) return;

    const currentWidgets = node.visualization.widgets || [];
    let newWidgets;

    if (editingWidgetIndex !== null) {
        // Edit existing
        newWidgets = [...currentWidgets];
        newWidgets[editingWidgetIndex] = updatedWidget;
    } else {
        // Add new
        newWidgets = [...currentWidgets, updatedWidget];
    }

    onUpdateNodeViz(node.id, { widgets: newWidgets });
    setEditingWidgetIndex(null);
  };

  const handleUpdateRecord = (storeId: string, recordId: string, field: string, value: any) => {
    const stores = activeData?.projectData?.stores || [];
    if (stores.length === 0) return;

    const newStores = stores.map(store => {
        if (store.id === storeId) {
            return {
                ...store,
                records: store.records.map(r => {
                    if (r.id === recordId) {
                        return { ...r, [field]: value };
                    }
                    return r;
                })
            };
        }
        return store;
    });

    // Only allow updating current state, not historical snapshots
    if (!viewingSnapshot) {
        onUpdateNodeData(node.id, { projectData: { stores: newStores } });
    }
  };

  const hasDebugError = !!node.debugInfo?.error;

  const getVizHeight = () => {
     switch(vizMode) {
         case 'minimized': return '48px';
         case 'normal': return '45%';
         case 'large': return '75%';
         case 'maximized': return '100%';
     }
  };

  const VizControl: React.FC<{ 
    mode: typeof vizMode, 
    label: string, 
    icon: React.ReactNode, 
    isActive: boolean 
  }> = ({ mode, label, icon, isActive }) => (
    <button
        onClick={(e) => { e.stopPropagation(); setVizMode(mode); }}
        className={`p-1.5 rounded-lg transition-all ${isActive ? 'bg-indigo-100 text-indigo-600' : 'text-slate-400 hover:text-slate-600 hover:bg-slate-100'}`}
        title={label}
    >
        {icon}
    </button>
  );

  const isMaximized = vizMode === 'maximized' || vizMode === 'large';
  const isFullscreen = vizMode === 'maximized';

  const activeData = viewingSnapshot ? viewingSnapshot.data : node.data;
  const activeViz = viewingSnapshot ? viewingSnapshot.viz : node.visualization;
  const activeProjectData = activeData?.projectData;

  const snapshotIndices = node.chat
    .map((m, i) => (m.visualizationSnapshot && m.dataSnapshot ? i : -1))
    .filter(i => i !== -1);

  const currentSnapshotIndexInList = viewingSnapshot ? snapshotIndices.indexOf(viewingSnapshot.index) : -1;
  const hasPrevSnapshot = viewingSnapshot ? currentSnapshotIndexInList > 0 : snapshotIndices.length > 0;
  const hasNextSnapshot = viewingSnapshot ? true : false;

  const loadSnapshot = (index: number) => {
      const msg = node.chat[index];
      if (msg && msg.visualizationSnapshot && msg.dataSnapshot) {
          setViewingSnapshot({
              viz: msg.visualizationSnapshot,
              data: msg.dataSnapshot,
              index: index
          });
      }
  };

  const handlePrevSnapshot = () => {
    if (!viewingSnapshot) {
        const last = snapshotIndices[snapshotIndices.length - 1];
        if (last !== undefined) loadSnapshot(last);
        return;
    }
    if (currentSnapshotIndexInList > 0) {
        loadSnapshot(snapshotIndices[currentSnapshotIndexInList - 1]);
    }
  };

  const handleNextSnapshot = () => {
     if (!viewingSnapshot) return;
     if (currentSnapshotIndexInList < snapshotIndices.length - 1) {
         loadSnapshot(snapshotIndices[currentSnapshotIndexInList + 1]);
     } else {
         setViewingSnapshot(null);
     }
  };

  const getLoadingText = () => {
      switch(node.processingStage) {
          case 'analyzing': return 'Analyzing project requirements...';
          case 'updating_data': return 'Updating database & schemas...';
          case 'designing_ui': return 'Designing interface components...';
          case 'rendering': return 'Rendering visualizations...';
