      }
  };

  return (
    <div className="flex flex-col h-full bg-slate-50 relative pb-[110px]">
      <ConfirmationModal 
        isOpen={confirmRevertIndex !== null}
        onConfirm={() => {
            const idx = confirmRevertIndex!;
